import{_ as r,o as t,c as s,j as e,a as l,a1 as i}from"./chunks/framework.Bp7r_-XI.js";const u=JSON.parse('{"title":"“独身魔咒”（Celibate Curse）","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/杂项/“独身魔咒”（Celibate Curse）.md","filePath":"4.资源分区/6.技艺及称号/杂项/“独身魔咒”（Celibate Curse）.md"}'),b={name:"4.资源分区/6.技艺及称号/杂项/“独身魔咒”（Celibate Curse）.md"};function n(o,a,_,d,c,p){return t(),s("div",null,[...a[0]||(a[0]=[e("h1",{id:"独身魔咒-celibate-curse",tabindex:"-1"},[l("“独身魔咒”（Celibate Curse） "),e("a",{class:"header-anchor",href:"#独身魔咒-celibate-curse","aria-label":'Permalink to "“独身魔咒”（Celibate Curse）"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：绯红庆典040")])])],-1),i('<h1 id="独身魔咒-celibate-curse-1" tabindex="-1">“独身魔咒”（Celibate Curse） <a class="header-anchor" href="#独身魔咒-celibate-curse-1" aria-label="Permalink to &quot;“独身魔咒”（Celibate Curse）&quot;">​</a></h1><p>“独身魔咒”（Celibate Curse）<br> 价格：750<br> 独身魔咒，也叫【三十岁还是处男就会专职成为魔法师】。<br> 据说，独身魔咒与一个古老的秘密组织——被称为“永恒独身者”（Eternal Celibates）的团体有关。这个组织由一群在中世纪时期的隐士、神秘学者和被社会边缘化的魔法师组成。他们相信，通过保持独身，他们能够达到更高的精神和魔法境界。<br> 在一次秘密的仪式中，团体的领袖，一位强大的魔法师，试图召唤一个古老的力量，以证明他们的信念。然而，仪式出了差错，不仅未能召唤出力量，反而释放了一个不可预见的诅咒，这个诅咒迅速蔓延到了世界各地。<br> 从那时起，每当一个满足要求的男性到达30周岁，他就会意外地获得魔法能力。</p><p>【觉醒之夜】<br> 如若一个男性满足以下前提。<br> -外貌在3或3以上，身体健康无勃起障碍，从未与他人进行过性O，即身为处男，便会在30岁的生日夜晚觉醒。<br> 随着午夜的钟声敲响，觉醒者身体内一股不可名状的能量突然涌现，充满了整个空间。空气中弥漫着一种奇异的香气，像是陈旧的图书馆和新鲜雨水的混合。<br> 如此，人物获得魔力能量池，类型为生命魔力。<br> 当觉醒之夜结束，黎明的到来。被诅咒者感到疲惫但满足，他们知道自己的生活已经永远改变，他们变为了一种新的生物——纯心者。</p><p>【纯心者】<br> 因为人物难能可贵的纯洁？，人物将在诅咒的影响下变为另一种生物，神秘学中称之为纯心者。纯心者视为一种【光明生物】，在肉体年龄被永恒的停留在觉醒之夜，这是C级【免疫衰老】的效果。从此以后，纯心者与面对自己孤独而漫长的人生。<br> 若人物在获得能力后失去处男身份，无论是主动还是被迫（例如被魅魔榨取），都会立即失去纯心者的身份和该能力提供的一切好处，生物类型也因人物的不自爱变得堕落，转变为【黑暗生物】。</p><p>变体：若ST允许，女性也可以获得这一能力，限制和效果相同，但名称为【魔女】。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',7)])])}const h=r(b,[["render",n]]);export{u as __pageData,h as default};
